function normalize(v){const l=Math.sqrt(v[0]*v[0]+v[1]*v[1]+v[2]*v[2]);return[v[0]/l,v[1]/l,v[2]/l];}
const L0=normalize([0.6,0.8,0.5]);
const L1=normalize([-0.5,0.3,0.7]);
const L2=normalize([0.0,-0.5,-0.8]);

// 3x3 matrix multiply (row-major flat arrays)
function mmul(A,B){
  const R=new Float32Array(9);
  for(let i=0;i<3;i++)for(let j=0;j<3;j++)for(let k=0;k<3;k++)R[i*3+j]+=A[i*3+k]*B[k*3+j];
  return R;
}
function mvec(M,x,y,z){
  return [M[0]*x+M[1]*y+M[2]*z, M[3]*x+M[4]*y+M[5]*z, M[6]*x+M[7]*y+M[8]*z];
}
function mry(a){const c=Math.cos(a),s=Math.sin(a);return new Float32Array([c,0,s,0,1,0,-s,0,c]);}
function mrx(a){const c=Math.cos(a),s=Math.sin(a);return new Float32Array([1,0,0,0,c,-s,0,s,c]);}

const el=document.getElementById('ascii-CAT');
// clear any existing text so the bunny has its own space
el && (el.textContent = '');

function render(){
  const M=mmul(mrx(angX),mry(angY));
  zbuf.fill(-Infinity);
  const SX=0.88/zoom, SY=1.05/zoom;
  const W1=W-1, H1=H-1;

  for(let fi=0;fi<NF;fi++){
    const ai=F[fi*3],bi=F[fi*3+1],ci=F[fi*3+2];

    // Rotate vertices (divide by 1000 to get float coords)
    const [ax,ay,az]=mvec(M,V[ai*3]/1000,V[ai*3+1]/1000,V[ai*3+2]/1000);
    const [bx,by,bz]=mvec(M,V[bi*3]/1000,V[bi*3+1]/1000,V[bi*3+2]/1000);
    const [cx,cy,cz]=mvec(M,V[ci*3]/1000,V[ci*3+1]/1000,V[ci*3+2]/1000);

    // Orthographic projection (Y flipped: screen Y goes down)
    const pax=(ax/SX+1)*0.5*W1, pay=(1-ay/SY)*0.5*H1;
    const pbx=(bx/SX+1)*0.5*W1, pby=(1-by/SY)*0.5*H1;
    const pcx=(cx/SX+1)*0.5*W1, pcy=(1-cy/SY)*0.5*H1;

    // Signed area — negative means front-facing (Y-flip reverses winding)
    const area=(pbx-pax)*(pcy-pay)-(pby-pay)*(pcx-pax);
    if(area>=0) continue;

    // Bounding box
    const x0=Math.max(0,  Math.floor(Math.min(pax,pbx,pcx)));
    const x1=Math.min(W1, Math.ceil( Math.max(pax,pbx,pcx)));
    const y0=Math.max(0,  Math.floor(Math.min(pay,pby,pcy)));
    const y1=Math.min(H1, Math.ceil( Math.max(pay,pby,pcy)));

    // Rotate normals
    const [nax,nay,naz]=mvec(M,N[ai*3]/1000,N[ai*3+1]/1000,N[ai*3+2]/1000);
    const [nbx,nby,nbz]=mvec(M,N[bi*3]/1000,N[bi*3+1]/1000,N[bi*3+2]/1000);
    const [ncx,ncy,ncz]=mvec(M,N[ci*3]/1000,N[ci*3+1]/1000,N[ci*3+2]/1000);

    for(let py=y0;py<=y1;py++){
      for(let px=x0;px<=x1;px++){
        // Barycentric coords via edge functions
        const w0=(pcx-pbx)*(py-pby)-(pcy-pby)*(px-pbx);
        const w1=(pax-pcx)*(py-pcy)-(pay-pcy)*(px-pcx);
        const w2=(pbx-pax)*(py-pay)-(pby-pay)*(px-pax);
        if(w0>0||w1>0||w2>0) continue;
        const ba=w0/area, bb=w1/area, bc=w2/area;
        const z=az*ba+bz*bb+cz*bc;
        const idx=py*W+px;
        if(z<=zbuf[idx]) continue;
        zbuf[idx]=z;
        NB[idx*3  ]=nax*ba+nbx*bb+ncx*bc;
        NB[idx*3+1]=nay*ba+nby*bb+ncy*bc;
        NB[idx*3+2]=naz*ba+nbz*bb+ncz*bc;
      }
    }
  }

  // Shade pixels
  let out='';
  for(let row=0;row<H;row++){
    for(let col=0;col<W;col++){
      const idx=row*W+col;
      if(!isFinite(zbuf[idx])){out+=' ';continue;}
      let nx=NB[idx*3],ny=NB[idx*3+1],nz=NB[idx*3+2];
      const nl=Math.sqrt(nx*nx+ny*ny+nz*nz)+1e-9;
      nx/=nl;ny/=nl;nz/=nl;
      let lum=0.07
        +Math.max(0,nx*L0[0]+ny*L0[1]+nz*L0[2])*0.78
        +Math.max(0,nx*L1[0]+ny*L1[1]+nz*L1[2])*0.28
        +Math.max(0,nx*L2[0]+ny*L2[1]+nz*L2[2])*0.12;
      // Specular on key light
      const dot0=nx*L0[0]+ny*L0[1]+nz*L0[2];
      if(dot0>0){const rz=2*dot0*nz-L0[2];lum+=Math.pow(Math.max(0,rz),18)*0.55;}
      out+=CHARS[Math.min(NC-1,Math.floor(Math.min(1,Math.max(0,lum))*(NC-1)))];
    }
    out+='\n';
  }
  const lines = out.replace(/\n+$/,'').split('\n');
  let minLead = Infinity;
  for (const line of lines) {
    if (!line.trim()) continue;
    const lead = line.length - line.trimStart().length;
    if (lead < minLead) minLead = lead;
  }
  const normalized = lines
    .map(line => line.slice(Number.isFinite(minLead) ? minLead : 0).replace(/\s+$/,''))
    .join('\n');
  el.textContent=normalized;

  requestAnimationFrame(() => {
    const lcEl   = document.querySelector('.archive-column--left');
    const rcEl   = document.querySelector('.archive-column--right');
    const floatR = document.querySelector('.bunny-shape-float--right'); // in left col
    const floatL = document.querySelector('.bunny-shape-float--left');  // in right col
    if (!lcEl || !rcEl || !floatR || !floatL) return;

    const preRect = el.getBoundingClientRect();
    const lcRect  = lcEl.getBoundingClientRect();
    const rcRect  = rcEl.getBoundingClientRect();
    if (preRect.width <= 0) return;

    const allLines  = normalized.split('\n');
    const nLines    = allLines.length;
    const maxLineLen = Math.max(1, ...allLines.map(l => l.length));
    const charW     = preRect.width / maxLineLen;
    const charH    = preRect.height / nLines;
    const bh       = preRect.height;
    const lcW      = lcRect.width;
    const rcW      = rcRect.width;

    const lEdgePre = [];
    const rEdgePre = [];
    for (let r = 0; r < nLines; r++) {
      const row = allLines[r];
      let l = 0, ri = row.length - 1;
      while (l  <= ri && row[l]  === ' ') l++;
      while (ri >= l  && row[ri] === ' ') ri--;
      if (l > ri) {

        lEdgePre.push(lcW);
        rEdgePre.push(-rcW);
      } else {
        lEdgePre.push(l  * charW);
        rEdgePre.push((ri + 1) * charW);
      }
    }

    // Convert to column-local px and clamp
    const lEdgeLC = lEdgePre.map(x => Math.min(lcW, Math.max(0, preRect.left + x - lcRect.left)));
    const rEdgeRC = rEdgePre.map(x => Math.min(rcW, Math.max(0, preRect.left + x - rcRect.left)));

    // Vertical alignment: margin-top aligns float top with bunny top
    const lcMT = Math.max(0, preRect.top - lcRect.top);
    const rcMT = Math.max(0, preRect.top - rcRect.top);

    // --- Left column float:right ---
    // Blocks [lEdgeLC[r], lcW] at each row. Text flows in [0, lEdgeLC[r]].
    // Polygon (exclusion area, right portion of column):
    //   trace right boundary (lcW) and step left boundary (lEdgeLC) per row.
    {
      let pts = [];
      pts.push(`${lEdgeLC[0].toFixed(1)}px 0px`);
      pts.push(`${lcW}px 0px`);
      pts.push(`${lcW}px ${bh.toFixed(1)}px`);
      for (let r = nLines - 1; r >= 0; r--) {
        pts.push(`${lEdgeLC[r].toFixed(1)}px ${((r + 1) * charH).toFixed(1)}px`);
        pts.push(`${lEdgeLC[r].toFixed(1)}px ${(r * charH).toFixed(1)}px`);
      }
      floatR.style.marginTop    = `${lcMT.toFixed(1)}px`;
      floatR.style.width        = `${lcW}px`;
      floatR.style.height       = `${bh.toFixed(1)}px`;
      floatR.style.shapeOutside = `polygon(${pts.join(', ')})`;
      floatR.style.shapeMargin  = '0px';
    }

    {
      let pts = [];
      pts.push('0px 0px');
      for (let r = 0; r < nLines; r++) {
        pts.push(`${rEdgeRC[r].toFixed(1)}px ${(r * charH).toFixed(1)}px`);
        pts.push(`${rEdgeRC[r].toFixed(1)}px ${((r + 1) * charH).toFixed(1)}px`);
      }
      pts.push(`0px ${bh.toFixed(1)}px`);
      floatL.style.marginTop    = `${rcMT.toFixed(1)}px`;
      floatL.style.width        = `${rcW}px`;
      floatL.style.height       = `${bh.toFixed(1)}px`;
      floatL.style.shapeOutside = `polygon(${pts.join(', ')})`;
      floatL.style.shapeMargin  = '0px';
    }
  });
}

function loop(){
  angY = -((mouseX / window.innerWidth) - 0.5) * Math.PI;
  angX = -((mouseY / window.innerHeight) - 0.5) * Math.PI * 0.8;
  angX = Math.max(-1.5, Math.min(1.5, angX));
  render();
  requestAnimationFrame(loop);
}
loop();

let lastHeartTime = 0;
function spawnHeart(x, y) {
  const now = Date.now();
  if (now - lastHeartTime < 80) return;
  lastHeartTime = now;
  const heart = document.createElement("div");
  heart.className = "ascii-heart";
  heart.textContent = "<3";
  const offsetX = (Math.random() - 0.5) * 30;
  const offsetY = (Math.random() - 0.5) * 30;
  heart.style.left = (x + offsetX - 10) + "px";
  heart.style.top = (y + offsetY - 10) + "px";
  document.body.appendChild(heart);
  setTimeout(() => heart.remove(), 1200);
}

el.addEventListener('mousedown',e=>{drag=true;autoRot=false;lmx=e.clientX;lmy=e.clientY;});
window.addEventListener('mousemove',e=>{
  mouseX=e.clientX;mouseY=e.clientY;
  if(!drag)return;
  if(e.target === el) spawnHeart(e.clientX, e.clientY);
  angY+=(e.clientX-lmx)*0.012;angX+=(e.clientY-lmy)*0.012;
  angX=Math.max(-1.5,Math.min(1.5,angX));lmx=e.clientX;lmy=e.clientY;
});
window.addEventListener('mouseup',()=>drag=false);
el.addEventListener('dblclick',()=>autoRot=true);
el.addEventListener('touchstart',e=>{autoRot=false;lmx=e.touches[0].clientX;lmy=e.touches[0].clientY;},{passive:true});
el.addEventListener('touchmove',e=>{
  if (e.target === el) spawnHeart(e.touches[0].clientX, e.touches[0].clientY);
  angY+=(e.touches[0].clientX-lmx)*0.013;angX+=(e.touches[0].clientY-lmy)*0.013;
  angX=Math.max(-1.5,Math.min(1.5,angX));lmx=e.touches[0].clientX;lmy=e.touches[0].clientY;
},{passive:true});
el.addEventListener('wheel',e=>{
  e.preventDefault();
},{passive:false});